import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    public void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeUserInput = sanitizeUserInput(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<p>User input: " + safeUserInput + "</p>"); // Properly sanitized user input
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input validation and sanitization here
        // For example, you can use OWASP ESAPI library or HTML escaping functions
        return userInput.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

